    43→// Manages subscriptions to one or more type of resource. The logical protocol
    44→// state of those subscription(s) is handled by SubscriptionState.
    45→// This class owns the GrpcStream used to talk to the server, maintains queuing
    46→// logic to properly order the subscription(s)' various messages, and allows
    47→// starting/stopping/pausing of the subscriptions.
    48→//
    49→// @tparam S SubscriptionState state type, either SotwSubscriptionState or DeltaSubscriptionState
    50→// @tparam F SubscriptionStateFactory type, either SotwSubscriptionStateFactory or
    51→// DeltaSubscriptionStateFactory
    52→// @tparam RQ Xds request type, either envoy::service::discovery::v3::DiscoveryRequest or
    53→// envoy::service::discovery::v3::DeltaDiscoveryRequest
    54→// @tparam RS Xds response type, either envoy::service::discovery::v3::DiscoveryResponse or
    55→// envoy::service::discovery::v3::DeltaDiscoveryResponse
    56→//
    57→template <class S, class F, class RQ, class RS>
    58→class GrpcMuxImpl : public GrpcStreamCallbacks<RS>,
    59→                    public GrpcMux,
    60→                    public ShutdownableMux,
    61→                    Logger::Loggable<Logger::Id::config> {
    62→public:
    63→  GrpcMuxImpl(std::unique_ptr<F> subscription_state_factory, GrpcMuxContext& grpc_mux_context);
    64→
    65→  ~GrpcMuxImpl() override;
    66→
    67→  // Causes all GrpcMuxImpl objects to stop sending any messages on `grpc_stream_` to fix a crash
    68→  // on Envoy shutdown due to dangling pointers. This may not be the ideal fix; it is probably
    69→  // preferable for the `ServerImpl` to cause all configuration subscriptions to be shutdown, which
    70→  // would then cause all `GrpcMuxImpl` to be destructed.
    71→  // TODO: figure out the correct fix: https://github.com/envoyproxy/envoy/issues/15072.
    72→  static void shutdownAll();
    73→
    74→  void shutdown() override { shutdown_ = true; }
    75→  bool isShutdown() { return shutdown_; }
    76→
    77→  // TODO (dmitri-d) return a naked pointer instead of the wrapper once the legacy mux has been
    78→  // removed and the mux interface can be changed
    79→  Config::GrpcMuxWatchPtr addWatch(const std::string& type_url,
    80→                                   const absl::flat_hash_set<std::string>& resources,
    81→                                   SubscriptionCallbacks& callbacks,
    82→                                   OpaqueResourceDecoderSharedPtr resource_decoder,
    83→                                   const SubscriptionOptions& options) override;
    84→  void updateWatch(const std::string& type_url, Watch* watch,
    85→                   const absl::flat_hash_set<std::string>& resources,
    86→                   const SubscriptionOptions& options);
    87→  void removeWatch(const std::string& type_url, Watch* watch);
    88→
    89→  ScopedResume pause(const std::string& type_url) override;
    90→  ScopedResume pause(const std::vector<std::string> type_urls) override;
    91→  void start() override;
    92→  const absl::flat_hash_map<std::string, std::unique_ptr<S>>& subscriptions() const {
    93→    return subscriptions_;
    94→  }
    95→
    96→  // GrpcStreamCallbacks
    97→  void onStreamEstablished() override { handleEstablishedStream(); }
    98→  void onEstablishmentFailure(bool next_attempt_may_send_initial_resource_version) override {
    99→    handleStreamEstablishmentFailure(next_attempt_may_send_initial_resource_version);
   100→  }
   101→  void onWriteable() override { trySendDiscoveryRequests(); }
   102→  void onDiscoveryResponse(std::unique_ptr<RS>&& message,
   103→                           ControlPlaneStats& control_plane_stats) override {
   104→    genericHandleResponse(message->type_url(), *message, control_plane_stats);
   105→  }
   106→
   107→  absl::Status
   108→  updateMuxSource(Grpc::RawAsyncClientSharedPtr&& primary_async_client,
   109→                  Grpc::RawAsyncClientSharedPtr&& failover_async_client, Stats::Scope& scope,
   110→                  BackOffStrategyPtr&& backoff_strategy,
   111→                  const envoy::config::core::v3::ApiConfigSource& ads_config_source) override;
   112→
   113→  EdsResourcesCacheOptRef edsResourcesCache() override {
   114→    return makeOptRefFromPtr(eds_resources_cache_.get());
   115→  }
   116→
   117→  GrpcStreamInterface<RQ, RS>& grpcStreamForTest() {
   118→    // TODO(adisuissa): Once envoy.restart_features.xds_failover_support is deprecated,
   119→    // return grpc_stream_.currentStreamForTest() directly (defined in GrpcMuxFailover).
   120→    if (Runtime::runtimeFeatureEnabled("envoy.restart_features.xds_failover_support")) {
   121→      return dynamic_cast<GrpcMuxFailover<RQ, RS>*>(grpc_stream_.get())->currentStreamForTest();
   122→    }
   123→    return *grpc_stream_.get();
   124→  }
