   301→absl::Status
   302→GrpcMuxImpl::updateMuxSource(Grpc::RawAsyncClientSharedPtr&& primary_async_client,
   303→                             Grpc::RawAsyncClientSharedPtr&& failover_async_client,
   304→                             Stats::Scope& scope, BackOffStrategyPtr&& backoff_strategy,
   305→                             const envoy::config::core::v3::ApiConfigSource& ads_config_source) {
   306→  // Process the rate limit settings.
   307→  absl::StatusOr<RateLimitSettings> rate_limit_settings_or_error =
   308→      Utility::parseRateLimitSettings(ads_config_source);
   309→  RETURN_IF_NOT_OK_REF(rate_limit_settings_or_error.status());
   310→
   311→  const Protobuf::MethodDescriptor& service_method =
   312→      *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(
   313→          "envoy.service.discovery.v3.AggregatedDiscoveryService.StreamAggregatedResources");
   314→
   315→  // Disconnect from current xDS servers.
   316→  ENVOY_LOG_MISC(info, "Replacing xDS gRPC mux source");
   317→  grpc_stream_->closeStream();
   318→  grpc_stream_ = createGrpcStreamObject(std::move(primary_async_client),
   319→                                        std::move(failover_async_client), service_method, scope,
   320→                                        std::move(backoff_strategy), *rate_limit_settings_or_error);
   321→  // No need to update the config_validators_ as they may contain some state
   322→  // that needs to be kept across different GrpcMux objects.
   323→
   324→  // Start the subscriptions over the grpc_stream.
   325→  grpc_stream_->establishNewStream();
