    70→      skip_subsequent_node_(grpc_mux_context.skip_subsequent_node_),
    71→      config_validators_(std::move(grpc_mux_context.config_validators_)),
    72→      xds_config_tracker_(grpc_mux_context.xds_config_tracker_),
    73→      xds_resources_delegate_(grpc_mux_context.xds_resources_delegate_),
    74→      eds_resources_cache_(std::move(grpc_mux_context.eds_resources_cache_)),
    75→      target_xds_authority_(grpc_mux_context.target_xds_authority_),
    76→      dynamic_update_callback_handle_(
    77→          grpc_mux_context.local_info_.contextProvider().addDynamicContextUpdateCallback(
    78→              [this](absl::string_view resource_type_url) {
    79→                onDynamicContextUpdate(resource_type_url);
    80→                return absl::OkStatus();
    81→              })) {
    82→  THROW_IF_NOT_OK(Config::Utility::checkLocalInfo("ads", local_info_));
    83→  AllMuxes::get().insert(this);
    84→}
