   152→void GrpcMuxImpl::onDynamicContextUpdate(absl::string_view resource_type_url) {
   153→  auto api_state = api_state_.find(resource_type_url);
   154→  if (api_state == api_state_.end()) {
   155→    return;
   156→  }
   157→  api_state->second->must_send_node_ = true;
   158→  queueDiscoveryRequest(resource_type_url);
   159→}
