   562→void GrpcMuxImpl::onWriteable() { drainRequests(); }
   563→
   564→void GrpcMuxImpl::onStreamEstablished() {
   565→  first_stream_request_ = true;
   566→  grpc_stream_->maybeUpdateQueueSizeStat(0);
   567→  clearNonce();
   568→  request_queue_ = std::make_unique<std::queue<std::string>>();
   569→  for (const auto& type_url : subscriptions_) {
   570→    queueDiscoveryRequest(type_url);
   571→  }
   572→}
   573→
   574→void GrpcMuxImpl::onEstablishmentFailure(bool) {
   575→  for (const auto& api_state : api_state_) {
   576→    for (auto watch : api_state.second->watches_) {
   577→      watch->callbacks_.onConfigUpdateFailed(
   578→          Envoy::Config::ConfigUpdateFailureReason::ConnectionFailure, nullptr);
   579→    }
   580→    if (!api_state.second->previously_fetched_data_) {
   581→      // On the initialization of the gRPC mux, if connection to the xDS server fails, load the
   582→      // persisted config, if available. The locally persisted config will be used until
   583→      // connectivity is established with the xDS server.
   584→      loadConfigFromDelegate(
   585→          /*type_url=*/api_state.first,
   586→          absl::flat_hash_set<std::string>{api_state.second->request_.resource_names().begin(),
   587→                                           api_state.second->request_.resource_names().end()});
   588→      api_state.second->previously_fetched_data_ = true;
   589→    }
   590→  }
   591→}
   592→
   593→void GrpcMuxImpl::queueDiscoveryRequest(absl::string_view queue_item) {
   594→  if (!grpc_stream_->grpcStreamAvailable()) {
   595→    ENVOY_LOG(debug, "No stream available to queueDiscoveryRequest for {}", queue_item);
   596→    return; // Drop this request; the reconnect will enqueue a new one.
   597→  }
   598→  ApiState& api_state = apiStateFor(queue_item);
   599→  if (api_state.paused()) {
   600→    ENVOY_LOG(trace, "API {} paused during queueDiscoveryRequest(), setting pending.", queue_item);
   601→    api_state.pending_ = true;
   602→    return; // Drop this request; the unpause will enqueue a new one.
   603→  }
   604→  request_queue_->emplace(std::string(queue_item));
   605→  drainRequests();
   606→}
   607→
   608→void GrpcMuxImpl::expiryCallback(absl::string_view type_url,
   609→                                 const std::vector<std::string>& expired) {
   610→  // The TtlManager triggers a callback with a list of all the expired elements, which we need
   611→  // to compare against the various watched resources to return the subset that each watch is
   612→  // subscribed to.
   613→
   614→  // We convert the incoming list into a set in order to more efficiently perform this
   615→  // comparison when there are a lot of watches.
   616→  absl::flat_hash_set<std::string> all_expired;
   617→  all_expired.insert(expired.begin(), expired.end());
   618→
   619→  // Note: We can blindly dereference the lookup here since the only time we call this is in a
   620→  // callback that is created at the same time as we insert the ApiState for this type.
   621→  for (auto watch : api_state_.find(type_url)->second->watches_) {
   622→    Protobuf::RepeatedPtrField<std::string> found_resources_for_watch;
   623→
   624→    for (const auto& resource : expired) {
   625→      if (all_expired.find(resource) != all_expired.end()) {
   626→        found_resources_for_watch.Add(std::string(resource));
   627→      }
   628→    }
   629→
   630→    THROW_IF_NOT_OK(watch->callbacks_.onConfigUpdate({}, found_resources_for_watch, ""));
   631→  }
   632→}
   633→
   634→GrpcMuxImpl::ApiState& GrpcMuxImpl::apiStateFor(absl::string_view type_url) {
   635→  auto itr = api_state_.find(type_url);
   636→  if (itr == api_state_.end()) {
   637→    api_state_.emplace(
   638→        type_url, std::make_unique<ApiState>(dispatcher_, [this, type_url](const auto& expired) {
   639→          expiryCallback(type_url, expired);
   640→        }));
   641→  }
   642→
   643→  return *api_state_.find(type_url)->second;
   644→}
   645→
   646→void GrpcMuxImpl::drainRequests() {
   647→  while (!request_queue_->empty() && grpc_stream_->checkRateLimitAllowsDrain()) {
   648→    // Process the request, if rate limiting is not enabled at all or if it is under rate limit.
   649→    sendDiscoveryRequest(request_queue_->front());
   650→    request_queue_->pop();
   651→  }
   652→  grpc_stream_->maybeUpdateQueueSizeStat(request_queue_->size());
   653→}
