   128→template <class S, class F, class RQ, class RS>
   129→Config::GrpcMuxWatchPtr GrpcMuxImpl<S, F, RQ, RS>::addWatch(
   130→    const std::string& type_url, const absl::flat_hash_set<std::string>& resources,
   131→    SubscriptionCallbacks& callbacks, OpaqueResourceDecoderSharedPtr resource_decoder,
   132→    const SubscriptionOptions& options) {
   133→  auto watch_map = watch_maps_.find(type_url);
   134→  if (watch_map == watch_maps_.end()) {
   135→    // Resource cache is only used for EDS resources.
   136→    EdsResourcesCacheOptRef resources_cache{absl::nullopt};
   137→    if (eds_resources_cache_ &&
   138→        (type_url == Config::getTypeUrl<envoy::config::endpoint::v3::ClusterLoadAssignment>())) {
   139→      resources_cache = makeOptRefFromPtr(eds_resources_cache_.get());
   140→    }
   141→
   142→    // We don't yet have a subscription for type_url! Make one!
   143→    watch_map = watch_maps_
   144→                    .emplace(type_url,
   145→                             std::make_unique<WatchMap>(options.use_namespace_matching_, type_url,
   146→                                                        config_validators_.get(), resources_cache))
   147→                    .first;
   148→    subscriptions_.emplace(type_url, subscription_state_factory_->makeSubscriptionState(
   149→                                         type_url, *watch_maps_[type_url], resource_decoder,
   150→                                         xds_config_tracker_, xds_resources_delegate_,
   151→                                         target_xds_authority_));
   152→    subscription_ordering_.emplace_back(type_url);
   153→  }
   154→
   155→  Watch* watch = watch_map->second->addWatch(callbacks, *resource_decoder);
   156→  // updateWatch() queues a discovery request if any of 'resources' are not yet subscribed.
   157→  updateWatch(type_url, watch, resources, options);
   158→  return std::make_unique<WatchImpl>(type_url, watch, *this, options);
   159→}
