   233→template <class S, class F, class RQ, class RS>
   234→absl::Status GrpcMuxImpl<S, F, RQ, RS>::updateMuxSource(
   235→    Grpc::RawAsyncClientSharedPtr&& primary_async_client,
   236→    Grpc::RawAsyncClientSharedPtr&& failover_async_client, Stats::Scope& scope,
   237→    BackOffStrategyPtr&& backoff_strategy,
   238→    const envoy::config::core::v3::ApiConfigSource& ads_config_source) {
   239→  // Process the rate limit settings.
   240→  absl::StatusOr<RateLimitSettings> rate_limit_settings_or_error =
   241→      Utility::parseRateLimitSettings(ads_config_source);
   242→  RETURN_IF_NOT_OK_REF(rate_limit_settings_or_error.status());
   243→
   244→  const Protobuf::MethodDescriptor& service_method =
   245→      *Protobuf::DescriptorPool::generated_pool()->FindMethodByName(methodName());
   246→
   247→  // Disconnect from current xDS servers.
   248→  ENVOY_LOG_MISC(info, "Replacing the xDS gRPC mux source");
   249→  grpc_stream_->closeStream();
   250→  grpc_stream_ = createGrpcStreamObject(std::move(primary_async_client),
   251→                                        std::move(failover_async_client), service_method, scope,
   252→                                        std::move(backoff_strategy), *rate_limit_settings_or_error);
   253→  // No need to update the config_validators_ as they may contain some state
   254→  // that needs to be kept across different GrpcMux objects.
   255→
   256→  // Update the watch map's config validators.
   257→  for (auto& [type_url, watch_map] : watch_maps_) {
   258→    watch_map->setConfigValidators(config_validators_.get());
   259→  }
   260→
   261→  // Start the subscriptions over the grpc_stream.
   262→  grpc_stream_->establishNewStream();
   263→
   264→  return absl::OkStatus();
   265→}
