   328→template <class S, class F, class RQ, class RS>
   329→void GrpcMuxImpl<S, F, RQ, RS>::handleStreamEstablishmentFailure(
   330→    bool next_attempt_may_send_initial_resource_version) {
   331→  ENVOY_LOG(debug, "GrpcMuxImpl stream failed to establish");
   332→  // If this happens while Envoy is still initializing, the onConfigUpdateFailed() we ultimately
   333→  // call on CDS will cause LDS to start up, which adds to subscriptions_ here. So, to avoid a
   334→  // crash, the iteration needs to dance around a little: collect pointers to all
   335→  // SubscriptionStates, call on all those pointers we haven't yet called on, repeat if there are
   336→  // now more SubscriptionStates.
   337→  absl::flat_hash_map<std::string, S*> all_subscribed;
   338→  absl::flat_hash_map<std::string, S*> already_called;
   339→  do {
   340→    for (auto& [type_url, subscription_state] : subscriptions_) {
   341→      all_subscribed[type_url] = subscription_state.get();
   342→    }
   343→    for (auto& sub : all_subscribed) {
   344→      if (already_called.insert(sub).second) { // insert succeeded ==> not already called
   345→        sub.second->handleEstablishmentFailure();
   346→      }
   347→    }
   348→  } while (all_subscribed.size() != subscriptions_.size());
   349→  should_send_initial_resource_versions_ = next_attempt_may_send_initial_resource_version;
   350→}
