   410→// Checks whether external conditions allow sending a discovery request. (Does not check
   411→// whether we *want* to send a discovery request).
   412→template <class S, class F, class RQ, class RS>
   413→bool GrpcMuxImpl<S, F, RQ, RS>::canSendDiscoveryRequest(const std::string& type_url) {
   414→  RELEASE_ASSERT(
   415→      !pausable_ack_queue_.paused(type_url),
   416→      fmt::format("canSendDiscoveryRequest() called on paused type_url {}. Pausedness is "
   417→                  "supposed to be filtered out by whoWantsToSendDiscoveryRequest(). ",
   418→                  type_url));
   419→
   420→  if (!grpcStreamAvailable()) {
   421→    ENVOY_LOG(trace, "No stream available to send a discovery request for {}.", type_url);
   422→    return false;
   423→  } else if (!rateLimitAllowsDrain()) {
   424→    ENVOY_LOG(trace, "{} discovery request hit rate limit; will try later.", type_url);
   425→    return false;
   426→  }
   427→  return true;
   428→}
   429→
   430→// Checks whether we have something to say in a discovery request, which can be an ACK and/or
   431→// a subscription update. (Does not check whether we *can* send that discovery request).
   432→// Returns the type_url we should send the discovery request for (if any).
   433→// First, prioritizes ACKs over non-ACK subscription interest updates.
   434→// Then, prioritizes non-ACK updates in the order the various types
   435→// of subscriptions were activated.
   436→template <class S, class F, class RQ, class RS>
   437→absl::optional<std::string> GrpcMuxImpl<S, F, RQ, RS>::whoWantsToSendDiscoveryRequest() {
   438→  // All ACKs are sent before plain updates. trySendDiscoveryRequests() relies on this. So, choose
   439→  // type_url from pausable_ack_queue_ if possible, before looking at pending updates.
   440→  if (!pausable_ack_queue_.empty()) {
   441→    return pausable_ack_queue_.front().type_url_;
   442→  }
   443→  // If we're looking to send multiple non-ACK requests, send them in the order that their
   444→  // subscriptions were initiated.
   445→  for (const auto& sub_type : subscription_ordering_) {
   446→    auto& sub = subscriptionStateFor(sub_type);
   447→    if (sub.subscriptionUpdatePending() && !pausable_ack_queue_.paused(sub_type)) {
   448→      return sub_type;
   449→    }
   450→  }
   451→  return absl::nullopt;
   452→}
