   219→template <class S, class F, class RQ, class RS>
   220→ScopedResume GrpcMuxImpl<S, F, RQ, RS>::pause(const std::vector<std::string> type_urls) {
   221→  for (const auto& type_url : type_urls) {
   222→    pausable_ack_queue_.pause(type_url);
   223→  }
   224→
   225→  return std::make_unique<Cleanup>([this, type_urls]() {
   226→    for (const auto& type_url : type_urls) {
   227→      pausable_ack_queue_.resume(type_url);
   228→      trySendDiscoveryRequests();
   229→    }
   230→  });
   231→}
