   267→template <class S, class F, class RQ, class RS>
   268→void GrpcMuxImpl<S, F, RQ, RS>::sendGrpcMessage(RQ& msg_proto, S& sub_state) {
   269→  if (sub_state.dynamicContextChanged() || !anyRequestSentYetInCurrentStream() ||
   270→      !skipSubsequentNode()) {
   271→    msg_proto.mutable_node()->CopyFrom(localInfo().node());
   272→  }
   273→  sendMessage(msg_proto);
   274→  setAnyRequestSentYetInCurrentStream(true);
   275→  sub_state.clearDynamicContextChanged();
   276→}
