   278→template <class S, class F, class RQ, class RS>
   279→void GrpcMuxImpl<S, F, RQ, RS>::genericHandleResponse(const std::string& type_url,
   280→                                                      RS& response_proto,
   281→                                                      ControlPlaneStats& control_plane_stats) {
   282→  auto sub = subscriptions_.find(type_url);
   283→  if (sub == subscriptions_.end()) {
   284→    ENVOY_LOG(warn,
   285→              "The server sent an xDS response proto with type_url {}, which we have "
   286→              "not subscribed to. Ignoring.",
   287→              type_url);
   288→    return;
   289→  }
   290→
   291→  if (response_proto.has_control_plane()) {
   292→    control_plane_stats.identifier_.set(response_proto.control_plane().identifier());
   293→
   294→    if (response_proto.control_plane().identifier() != sub->second->controlPlaneIdentifier()) {
   295→      sub->second->setControlPlaneIdentifier(response_proto.control_plane().identifier());
   296→      ENVOY_LOG(debug, "Receiving gRPC updates for {} from {}", response_proto.type_url(),
   297→                sub->second->controlPlaneIdentifier());
   298→    }
   299→  }
   300→
   301→  pausable_ack_queue_.push(sub->second->handleResponse(response_proto));
   302→  trySendDiscoveryRequests();
   303→  Memory::Utils::tryShrinkHeap();
   304→}
