   352→template <class S, class F, class RQ, class RS>
   353→S& GrpcMuxImpl<S, F, RQ, RS>::subscriptionStateFor(const std::string& type_url) {
   354→  auto sub = subscriptions_.find(type_url);
   355→  RELEASE_ASSERT(sub != subscriptions_.end(),
   356→                 fmt::format("Tried to look up SubscriptionState for non-existent subscription {}.",
